1	type Cell = [number, number];
2	
3	const areNeighbors = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
4	  (x1 !== x2 || y1 !== y2) && Math.abs(x1 - x2) <= 1 && Math.abs(y1 - y2) <= 1;
5	
6	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
7	  cells.filter((other) => areNeighbors(cell, other)).length;
8	
9	const isLive = (cell: Cell, cells: Cell[]): boolean =>
10	  cells.some(([x, y]) => x === cell[0] && y === cell[1]);
11	
12	const getCandidates = (cells: Cell[]): Cell[] => {
13	  const seen = new Set<string>();
14	  const result: Cell[] = [];
15	  for (const [x, y] of cells) {
16	    for (let dx = -1; dx <= 1; dx++) {
17	      for (let dy = -1; dy <= 1; dy++) {
18	        const nx = x + dx;
19	        const ny = y + dy;
20	        const key = `${nx},${ny}`;
21	        if (!seen.has(key)) {
22	          seen.add(key);
23	          result.push([nx, ny]);
24	        }
25	      }
26	    }
27	  }
28	  return result;
29	};
30	
31	export function nextGeneration(cells: Cell[]): Cell[] {
32	  return getCandidates(cells).filter((cell) => {
33	    const liveNeighbors = countLiveNeighbors(cell, cells);
34	    return liveNeighbors === 3 || (liveNeighbors === 2 && isLive(cell, cells));
35	  });
36	}
