1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block still life unchanged", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(input);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(input));
19	  });
20	  it("should oscillate a vertical blinker to horizontal", () => {
21	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(input);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(expected));
26	  });
27	  it("should keep a live cell alive with 3 neighbors (survival)", () => {
28	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1]];
29	    const result = nextGeneration(input);
30	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
31	  });
32	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
33	    const input: [number, number][] = [[0, 0], [1, 0], [2, 0], [1, 1], [1, -1]];
34	    const result = nextGeneration(input);
35	    expect(result).not.toEqual(expect.arrayContaining([[1, 0]]));
36	  });
37	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
38	    const input: [number, number][] = [[0, 2], [1, 2], [0, 1]];
39	    const result = nextGeneration(input);
40	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
41	  });
42	  it("should handle cells with negative coordinates", () => {
43	    const input: [number, number][] = [[-2, -2], [-1, -2], [-2, -1], [-1, -1]];
44	    const result = nextGeneration(input);
45	    expect(result).toHaveLength(4);
46	    expect(result).toEqual(expect.arrayContaining(input));
47	  });
