  const seen = new Set<string>();
  const result: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const nx = x + dx;
        const ny = y + dy;
        const key = `${nx},${ny}`;
        if (!seen.has(key)) {
          seen.add(key);
          result.push([nx, ny]);
        }
      }
    }
  }
  return result;
};

